import fs from 'fs';
import path from 'path';
import { program } from 'commander';

// Abstract strategy interface
interface FileProcessStrategy {
  process(file: string, dryRun: boolean): [string, string];
}

// Concrete strategy implementation for regex-based renaming
class RegexRenameStrategy implements FileProcessStrategy {
  private pattern: RegExp;
  private replacement: string;

  constructor(pattern: string, replacement: string) {
    this.pattern = new RegExp(pattern);
    this.replacement = replacement;
  }

  process(file: string, dryRun: boolean): [string, string] {
    const directory = path.dirname(file);
    const filename = path.basename(file);
    const newFilename = filename.replace(this.pattern, this.replacement);
    const newPath = path.join(directory, newFilename);

    if (!dryRun && newPath !== file) {
      fs.renameSync(file, newPath);
    }

    return [file, newPath];
  }
}

// Main file processor class
class FileProcessor {
  private strategy: FileProcessStrategy;

  constructor(strategy: FileProcessStrategy) {
    this.strategy = strategy;
  }

  processFiles(files: string[], dryRun: boolean): void {
    const results: [string, string][] = [];

    for (const file of files) {
      if (fs.statSync(file).isFile()) {
        results.push(this.strategy.process(file, dryRun));
      }
    }

    console.log(`\n${dryRun ? 'Dry run - ' : ''}Processing results:`);
    let changedCount = 0;

    for (const [original, newPath] of results) {
      const originalName = path.basename(original);
      const newName = path.basename(newPath);

      if (originalName !== newName) {
        console.log(`  ${originalName} -> ${newName}`);
        changedCount++;
      } else {
        console.log(`  ${originalName} (no change)`);
      }
    }

    console.log(`\nTotal files: ${results.length}, Changed: ${changedCount}`);
  }
}

// Parse command line arguments
program
  .name('bulk-rename')
  .description('Bulk file renamer using regex patterns')
  .requiredOption('-p, --pattern <pattern>', 'Regex pattern to match in filenames')
  .requiredOption('-r, --replacement <replacement>', 'Replacement string (can use regex groups)')
  .option('-d, --directory <directory>', 'Directory containing files to rename', process.cwd())
  .option('--recursive', 'Process files recursively', false)
  .option('-n, --dry-run', 'Show what would be changed without actually renaming', false)
  .parse(process.argv);

const options = program.opts();

try {
  // Get files from directory
  const getFiles = (dir: string, recursive: boolean): string[] => {
    const entries = fs.readdirSync(dir);
    let files: string[] = [];

    for (const entry of entries) {
      const fullPath = path.join(dir, entry);
      const stats = fs.statSync(fullPath);

      if (stats.isFile()) {
        files.push(fullPath);
      } else if (recursive && stats.isDirectory()) {
        files = files.concat(getFiles(fullPath, recursive));
      }
    }

    return files;
  };

  const directory = path.resolve(options.directory);
  if (!fs.existsSync(directory) || !fs.statSync(directory).isDirectory()) {
    throw new Error(`Directory not found: ${directory}`);
  }

  const files = getFiles(directory, options.recursive);
  if (files.length === 0) {
    console.log("No files found to process");
    process.exit(0);
  }

  // Create strategy and processor
  const strategy = new RegexRenameStrategy(options.pattern, options.replacement);
  const processor = new FileProcessor(strategy);

  // Process the files
  processor.processFiles(files, options.dryRun);

} catch (error) {
  console.error(`Error: ${error.message}`);
  process.exit(1);
}
