const WebSocket = require('ws');

// Strategy interface
class MessageHandler {
  handle(message, sender, wss) {
    throw new Error('handle() must be implemented');
  }
}

// Concrete strategies
class BroadcastHandler extends MessageHandler {
  handle(message, sender, wss) {
    wss.clients.forEach(client => {
      if (client !== sender && client.readyState === WebSocket.OPEN) {
        client.send(message);
      }
    });
  }
}

class EchoHandler extends MessageHandler {
  handle(message, sender, wss) {
    sender.send(`Echo: ${message}`);
  }
}

// Context
class MessageRouter {
  constructor() {
    this.handlers = new Map();
  }

  registerHandler(type, handler) {
    this.handlers.set(type, handler);
  }

  route(type, message, sender, wss) {
    const handler = this.handlers.get(type);
    if (handler) {
      handler.handle(message, sender, wss);
    }
  }
}

// WebSocket server
const wss = new WebSocket.Server({ port: 8080 });
const router = new MessageRouter();

// Register handlers
router.registerHandler('broadcast', new BroadcastHandler());
router.registerHandler('echo', new EchoHandler());

wss.on('connection', (ws) => {
  console.log('Client connected');

  ws.on('message', (data) => {
    try {
      const { type, message } = JSON.parse(data);
      router.route(type, message, ws, wss);
    } catch (e) {
      console.error('Invalid message format');
    }
  });

  ws.on('close', () => {
    console.log('Client disconnected');
  });
});

