  private generators: OutputGenerator[] = [];

  registerPlugin(plugin: Plugin): void {
    if (plugin.transformer) {
      this.transformers.push(plugin.transformer);
    }
    if (plugin.generator) {
      this.generators.push(plugin.generator);
    }
  }

  async processContent(markdown: string): Promise<Map<string, string>> {
