        self.product_repository = product_repository

    def get_product(self, product_id: int) -> Optional[Dict]:
        return self.product_repository.get_product_by_id(product_id)

    def get_all_products(self) -> List[Dict]:
        return self.product_repository.get_all_products()

    def create_product(self, product_details: Dict) -> int:
        # Business validation can go here
        if product_details.get('price', 0) <= 0:
            raise ValueError("Product price must be greater than zero")

        return self.product_repository.add_new_product(product_details)

    def modify_product(self, product_id: int, product_details: Dict) -> bool:
        # Business validation can go here
        if product_details.get('price', 0) <= 0:
            raise ValueError("Product price must be greater than zero")

        return self.product_repository.update_product(product_id, product_details)

    def remove_product(self, product_id: int) -> bool:
        return self.product_repository.delete_product(product_id)

    def update_stock(self, product_id: int, quantity_change: int) -> bool:
        product = self.get_product(product_id)
        if not product:
            return False

        new_stock = product['stock'] + quantity_change
        if new_stock < 0:
            raise ValueError("Insufficient stock")

        product['stock'] = new_stock
        return self.product_repository.update_product(product_id, product)

class CustomerService:
