        return self.customer_repository.get_customer_by_email(email)

    def register_customer(self, customer_details: Dict) -> int:
        # Check if email already exists
        existing_customer = self.get_customer_by_email(customer_details['email'])
        if existing_customer:
            raise ValueError("Email already registered")

        # Password hashing would typically happen here
        return self.customer_repository.add_new_customer(customer_details)

    def update_customer_info(self, customer_id: int, customer_details: Dict) -> bool:
        return self.customer_repository.update_customer(customer_id, customer_details)

class OrderService:
    def __init__(self, order_repository: OrderRepository, product_service: ProductService):
        self.order_repository = order_repository
        self.product_service = product_service

    def get_order(self, order_id: int) -> Optional[Dict]:
        order = self.order_repository.get_order_by_id(order_id)
        if order:
            order['items'] = self.order_repository.get_order_items(order_id)
        return order

    def get_customer_orders(self, customer_id: int) -> List[Dict]:
        return self.order_repository.get_orders_by_customer(customer_id)

    def place_order(self, order_details: Dict) -> int:
        # Calculate total from items
        total = 0
        items = order_details.get('items', [])

        if not items:
            raise ValueError("Order must contain at least one item")

        # Create the order first
        order_id = self.order_repository.create_order({
            'customer_id': order_details['customer_id'],
            'status': 'pending',
            'total': 0  # Will update after adding items
        })

        # Add items and update product stock
        for item in items:
            product = self.product_service.get_product(item['product_id'])
            if not product:
                raise ValueError(f"Product with ID {item['product_id']} not found")

            if product['stock'] < item['quantity']:
                raise ValueError(f"Insufficient stock for product {product['name']}")

            # Add order item
            self.order_repository.add_order_item(order_id, {
                'product_id': item['product_id'],
                'quantity': item['quantity'],
                'price': product['price']
            })

            # Update product stock
            self.product_service.update_stock(item['product_id'], -item['quantity'])

            # Add to total
            total += product['price'] * item['quantity']

        # Update order with final total
        cursor = self.order_repository.db_connection.cursor()
        cursor.execute('UPDATE orders SET total = ? WHERE id = ?', (total, order_id))
        self.order_repository.db_connection.commit()

        return order_id

    def update_order_status(self, order_id: int, status: str) -> bool:
        valid_statuses = ['pending', 'processing', 'shipped', 'delivered', 'cancelled']
        if status not in valid_statuses:
            raise ValueError(f"Invalid status. Must be one of: {', '.join(valid_statuses)}")

        return self.order_repository.update_order_status(order_id, status)

