import (
	"fmt"
	"log"
	"os"
	"os/signal"
	"sync"
	"syscall"
	"time"

	"github.com/streadway/amqp"
	"github.com/juju/ratelimit"
)

// SignupEvent represents a user signup event
type SignupEvent struct {
	UserID    string    `json:"user_id"`
	Email     string    `json:"email"`
	Timestamp time.Time `json:"timestamp"`
}

// Consumer handles consuming messages from RabbitMQ
type Consumer struct {
	conn       *amqp.Connection
	queue      string
	workers    int
	bucket     *ratelimit.Bucket
	wg         sync.WaitGroup
	stopChan   chan bool
}

// NewConsumer creates a new RabbitMQ consumer with rate limiting
func NewConsumer(amqpURL, queueName string, workers int, rateLimit float64) (*Consumer, error) {
	conn, err := amqp.Dial(amqpURL)
	if err != nil {
		return nil, fmt.Errorf("dial: %s", err)
	}

	bucket := ratelimit.NewBucketWithRate(rateLimit, int64(rateLimit))

	consumer := &Consumer{
		conn:       conn,
		queue:      queueName,
		workers:    workers,
		bucket:     bucket,
		stopChan:   make(chan bool),
	}
	return consumer, nil
}

// processMessage handles the business logic for a signup event
func (c *Consumer) processMessage(id int, body []byte) {
	log.Printf("Worker %d processing message: %s", id, body)
	// Simulate work
	time.Sleep(200 * time.Millisecond)
	log.Printf("Worker %d completed processing message", id)
}

// handleDelivery processes messages from the delivery channel
func (c *Consumer) handleDelivery(deliveries <-chan amqp.Delivery, id int) {
	defer c.wg.Done()
	log.Printf("Worker %d started", id)

	for {
		select {
		case d, ok := <-deliveries:
			if !ok {
				log.Printf("Worker %d: delivery channel closed", id)
				return
			}

			// Rate limit the consumer
			c.bucket.Wait(1)

			log.Printf("Worker %d received message: %s", id, d.Body)
			c.processMessage(id, d.Body)

			if err := d.Ack(false); err != nil {
				log.Printf("Worker %d error acknowledging message: %v", id, err)
			}

		case <-c.stopChan:
			log.Printf("Worker %d received stop signal", id)
			return
		}
	}
}

// Consume starts consuming messages from the queue
func (c *Consumer) Consume() error {
	ch, err := c.conn.Channel()
	if err != nil {
		return fmt.Errorf("channel: %s", err)
	}

	// Ensure the queue exists
	_, err = ch.QueueDeclare(
		c.queue, // name
		true,    // durable
		false,   // delete when unused
		false,   // exclusive
		false,   // no-wait
		nil,     // arguments
	)
	if err != nil {
		return fmt.Errorf("queue declare: %s", err)
	}

	// Set QoS for fair dispatch
	err = ch.Qos(
		1,     // prefetch count
		0,     // prefetch size
		false, // global
	)
	if err != nil {
		return fmt.Errorf("set QoS: %s", err)
	}

	deliveries, err := ch.Consume(
		c.queue, // queue
		"",      // consumer
		false,   // auto-ack
		false,   // exclusive
		false,   // no-local
		false,   // no-wait
		nil,     // args
	)
	if err != nil {
		return fmt.Errorf("queue consume: %s", err)
	}

	// Start workers
	for i := 0; i < c.workers; i++ {
		c.wg.Add(1)
		go c.handleDelivery(deliveries, i)
	}

	log.Printf("Started %d workers, consuming from queue %s", c.workers, c.queue)
	return nil
}

// Stop gracefully stops the consumer
func (c *Consumer) Stop() {
	log.Println("Stopping consumer...")
	close(c.stopChan)
	c.wg.Wait()
	c.conn.Close()
	log.Println("Consumer stopped")
}

func main() {
	// Set these values based on your AMQP server setup
	amqpURL := "amqp://guest:guest@localhost:5672/"
	queueName := "user_signups"
	workers := 5
	rateLimit := 10.0 // messages per second

	// Allow overriding settings via environment variables
	if envURL := os.Getenv("AMQP_URL"); envURL != "" {
		amqpURL = envURL
	}
	if envQueue := os.Getenv("QUEUE_NAME"); envQueue != "" {
		queueName = envQueue
	}

	consumer, err := NewConsumer(amqpURL, queueName, workers, rateLimit)
	if err != nil {
		log.Fatalf("Failed to create consumer: %s", err)
	}

	// Setup signal handling for graceful shutdown
	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	// Start consuming in a separate goroutine
	err = consumer.Consume()
	if err != nil {
		log.Fatalf("Failed to start consumer: %s", err)
	}

	// Wait for termination signal
	sig := <-sigChan
	log.Printf("Received signal %s, shutting down", sig)
	consumer.Stop()
}

use std::{collections::HashMap, env, process};
use std::io::{self, Write};
use std::fs::{File, OpenOptions};
use std::path::PathBuf;

const VERSION: &str = "1.0.0";

#[derive(Debug, Clone)]
struct Task {
    id: i32,
    description: String,
}

struct TaskManager {
    tasks: HashMap<i32, Task>,
    next_id: i32,
}

impl TaskManager {
    fn new() -> TaskManager {
        TaskManager {
            tasks: HashMap::new(),
            next_id: 1,
        }
    }

    fn add_task(&mut self, description: String) {
        let task = Task {
            id: self.next_id,
            description,
        };
        self.tasks.insert(self.next_id, task);
        self.next_id += 1;
    }

    fn remove_task(&mut self, id: i32) -> Result<(), String> {
        match self.tasks.remove(&id) {
            Some(_) => Ok(()),
            None => Err(format!("Task with ID {} does not exist.", id)),
        }
    }

    fn view_tasks(&self) -> String {
        if self.tasks.is_empty() {
            "No tasks available.".into()
        } else {
            self.tasks.values()
                .map(|task| format!("{}: {}", task.id, task.description))
                .collect::<Vec<String>>()
                .join("\n")
        }
    }
}

fn get_data_file() -> PathBuf {
    let mut path = dirs::home_dir().unwrap_or_else(|| PathBuf::from("."));
    path.push(".task_manager");
    std::fs::create_dir_all(&path).unwrap_or_else(|_| {
        eprintln!("Warning: Could not create data directory");
    });
    path.push("tasks.dat")
}

fn save_tasks(task_manager: &TaskManager) -> io::Result<()> {
    let file_path = get_data_file();
    let mut file = OpenOptions::new()
        .write(true)
        .create(true)
        .truncate(true)
        .open(file_path)?;

    for task in task_manager.tasks.values() {
        writeln!(file, "{}:{}", task.id, task.description)?;
    }

    Ok(())
}

fn load_tasks() -> TaskManager {
    let file_path = get_data_file();
    let mut task_manager = TaskManager::new();

    if let Ok(file) = File::open(file_path) {
        let reader = io::BufReader::new(file);
        let lines = io::BufRead::lines(reader);

        for line in lines.flatten() {
            if let Some(pos) = line.find(':') {
                if let Ok(id) = line[..pos].parse::<i32>() {
                    let description = line[pos+1..].to_string();
                    task_manager.tasks.insert(id, Task { id, description });
                    if id >= task_manager.next_id {
                        task_manager.next_id = id + 1;
                    }
                }
            }
        }
    }

    task_manager
}

fn main() {
    let args: Vec<String> = env::args().collect();
    let mut task_manager = load_tasks();

    if args.len() < 2 {
        print_help();
        return;
    }

    match args[1].as_str() {
        "--help" => print_help(),
        "--version" => println!("Task Manager version {}", VERSION),
        "add" => {
            if args.len() < 3 {
                eprintln!("Error: No description provided for add command.");
                process::exit(1);
            }

            let description = args[2..].join(" ");
            task_manager.add_task(description);
            if let Err(e) = save_tasks(&task_manager) {
                eprintln!("Error saving tasks: {}", e);
                process::exit(1);
            }
            println!("Task added successfully.");
        }
        "remove" => {
            if args.len() != 3 {
                eprintln!("Error: Please provide exactly one task ID for remove command.");
                process::exit(1);
            }

            let id = args[2].parse::<i32>();
            match id {
                Ok(id) => match task_manager.remove_task(id) {
                    Ok(_) => {
                        if let Err(e) = save_tasks(&task_manager) {
                            eprintln!("Error saving tasks: {}", e);
                            process::exit(1);
                        }
                        println!("Task removed successfully.");
                    },
                    Err(e) => {
                        eprintln!("Error: {}", e);
                        process::exit(1);
                    }
                },
                Err(_) => {
                    eprintln!("Error: Task ID must be a number.");
                    process::exit(1);
                }
            }
        }
        "view" => println!("{}", task_manager.view_tasks()),
        _ => {
            eprintln!("Error: Unknown command '{}'.", args[1]);
            print_help();
            process::exit(1);
        }
    }
}

fn print_help() {
    println!("Task Manager CLI");
    println!("Usage:");
    println!("  task_manager --help                         Displays this help message.");
    println!("  task_manager --version                      Displays the version of the task manager.");
    println!("  task_manager add <task_description>         Adds a new task with the given description.");
    println!("  task_manager remove <task_id>               Removes the task with the specified ID.");
    println!("  task_manager view                           Displays all tasks.");
}

