import React from 'react';
import styles from './Button.module.css';
import { BaseInputProps } from '../../types';

type ButtonVariant = 'primary' | 'secondary' | 'danger' | 'outline' | 'text';
type ButtonSize = 'small' | 'medium' | 'large';

interface ButtonProps extends BaseInputProps, React.ButtonHTMLAttributes<HTMLButtonElement> {
  /** Button click handler */
  onClick?: (e: React.MouseEvent<HTMLButtonElement>) => void;
  /** Button variant style */
  variant?: ButtonVariant;
  /** Button size */
  size?: ButtonSize;
  /** Show loading spinner */
  loading?: boolean;
  /** Icon to display before text */
  startIcon?: React.ReactNode;
  /** Icon to display after text */
  endIcon?: React.ReactNode;
  /** Button text content */
  children: React.ReactNode;
}

/**
 * Button component for form actions
 * 
 * @example
 * ```tsx
 * <Button 
 *   variant="primary" 
 *   size="medium" 
 *   onClick={() => console.log('Clicked!')}
 * >
 *   Submit Form
 * </Button>
 * ```
 */
const Button: React.FC<ButtonProps> = ({
  onClick,
  variant = 'primary',
  size = 'medium',
  className = '',
  disabled = false,
  loading = false,
  startIcon,
  endIcon,
  children,
  'data-testid': dataTestId,
  ...props
}) => {
  return (
    <button
      className={`
        ${styles.button}
        ${styles[variant]}
        ${styles[size]}
        ${loading ? styles.loading : ''}
        ${className}
      `}
      onClick={onClick}
      disabled={disabled || loading}
      data-testid={dataTestId}
      {...props}
    >
      {loading && <span className={styles.spinner} />}
      {!loading && startIcon && <span className={styles.startIcon}>{startIcon}</span>}
      <span className={styles.content}>{children}</span>
      {!loading && endIcon && <span className={styles.endIcon}>{endIcon}</span>}
    </button>
  );
};

export default Button;

