export class DistributedTaskQueue {
  private queueName: string;
  private pipeline: Redis | null = null;

  constructor(queueName: string) {
    this.queueName = queueName;
  }

  // Bulk enqueue with pipeline optimization
  async enqueueJobs(jobs: any[], batchSize: number = 1000): Promise<void> {
    const connection = getConnection();

    for (let i = 0; i < jobs.length; i += batchSize) {
      const batch = jobs.slice(i, i + batchSize);
      const pipeline = connection.pipeline();

      batch.forEach(job => {
        const jobData = JSON.stringify({
          id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
          data: job,
          timestamp: Date.now()
        });
        pipeline.rpush(this.queueName, jobData);
      });

      await pipeline.exec();
    }
  }

  // High-throughput job processing with batch operations
  async processBatch(batchSize: number, processor: (jobs: any[]) => Promise<void>): Promise<number> {
    const connection = getConnection();
    const pipeline = connection.pipeline();

    // Use BLPOP with timeout for efficient blocking
    const jobs: string[] = [];

    // Get multiple jobs in one operation
    for (let i = 0; i < batchSize; i++) {
      pipeline.lpop(this.queueName);
    }

    const results = await pipeline.exec();
    if (!results) return 0;

    const validJobs = results
      .filter(([err, result]) => !err && result)
      .map(([_, result]) => {
        try {
          return JSON.parse(result as string);
        } catch {
          return null;
        }
      })
      .filter(job => job !== null);

    if (validJobs.length === 0) return 0;

    // Process jobs in batch
    await processor(validJobs.map(job => job.data));

    return validJobs.length;
  }

  // Get queue length
  async getQueueLength(): Promise<number> {
    const connection = getConnection();
    return await connection.llen(this.queueName);
  }

  // Clear queue
  async clearQueue(): Promise<void> {
    const connection = getConnection();
    await connection.del(this.queueName);
  }
}

