// server.js - Backend Express server
import express from 'express';
import cookieParser from 'cookie-parser';
import csrf from 'csurf';
import helmet from 'helmet';
import cors from 'cors';
import { randomBytes, createHash } from 'crypto';
import axios from 'axios';

// OAuth 2.1 configuration
const config = {
  clientID: process.env.CLIENT_ID,
  clientSecret: process.env.CLIENT_SECRET,
  redirectUri: process.env.REDIRECT_URI,
  authorizationEndpoint: 'https://provider.com/oauth/authorize',
  tokenEndpoint: 'https://provider.com/oauth/token',
  refreshEndpoint: 'https://provider.com/oauth/token',
  cookieSecret: process.env.COOKIE_SECRET
};

// Create Express app
const app = express();

// Enable secure cookies
app.use(cookieParser(config.cookieSecret));

// Configure CSP headers
app.use(helmet.contentSecurityPolicy({
  directives: {
    defaultSrc: ["'self'"],
    scriptSrc: ["'self'"],
    connectSrc: ["'self'", "https://provider.com"],
    frameSrc: ["'none'"],
    objectSrc: ["'none'"],
    upgradeInsecureRequests: []
  }
}));

// Configure CORS for SPA
app.use(cors({
  origin: process.env.CLIENT_ORIGIN,
  credentials: true,
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type', 'X-CSRF-Token']
}));

// CSRF protection middleware
const csrfProtection = csrf({ cookie: { httpOnly: true, sameSite: 'strict', secure: true } });
app.use(csrfProtection);

// Inject CSRF token
app.use((req, res, next) => {
  res.locals.csrfToken = req.csrfToken();
  next();
});

// In-memory storage for PKCE and state (use Redis in production)
const stateStore = new Map();
const tokenStore = new Map();

// Generate secure random string for PKCE and state
const generateRandomString = (length = 64) => {
  return randomBytes(length).toString('hex');
};

// Generate code challenge from verifier using SHA-256
const generateCodeChallenge = (verifier) => {
  return createHash('sha256')
    .update(verifier)
    .digest('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
};

// Initialize OAuth login flow
app.get('/api/auth/login', (req, res) => {
  // Generate PKCE values
  const codeVerifier = generateRandomString();
  const codeChallenge = generateCodeChallenge(codeVerifier);

  // Generate state for CSRF protection
  const state = generateRandomString(32);

  // Store state and code verifier with expiry (5 minutes)
  stateStore.set(state, {
    codeVerifier,
    created: Date.now(),
    expires: Date.now() + (5 * 60 * 1000)
  });

  // Build authorization URL
  const authUrl = new URL(config.authorizationEndpoint);
  authUrl.searchParams.append('client_id', config.clientID);
  authUrl.searchParams.append('redirect_uri', config.redirectUri);
  authUrl.searchParams.append('response_type', 'code');
  authUrl.searchParams.append('scope', 'openid profile email');
  authUrl.searchParams.append('state', state);
  authUrl.searchParams.append('code_challenge', codeChallenge);
  authUrl.searchParams.append('code_challenge_method', 'S256');

  // Return the URL to the client
  res.json({ authUrl: authUrl.toString() });
});

// Handle OAuth callback
app.get('/api/auth/callback', async (req, res) => {
  const { code, state } = req.query;

  // Validate state parameter
  const storedState = stateStore.get(state);
  if (!storedState || storedState.expires < Date.now()) {
    stateStore.delete(state);
    return res.status(403).json({ error: 'Invalid or expired state parameter' });
  }

  // Extract code verifier and clean up state store
  const { codeVerifier } = storedState;
  stateStore.delete(state);

  try {
    // Exchange authorization code for tokens
    const tokenResponse = await axios.post(config.tokenEndpoint, new URLSearchParams({
      grant_type: 'authorization_code',
      client_id: config.clientID,
      client_secret: config.clientSecret,
      code,
      code_verifier: codeVerifier,
      redirect_uri: config.redirectUri
    }), {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      }
    });

    const { access_token, refresh_token, id_token, expires_in } = tokenResponse.data;

    // Generate session ID
    const sessionId = generateRandomString(32);

    // Store tokens securely on server side
    tokenStore.set(sessionId, {
      accessToken: access_token,
      refreshToken: refresh_token,
      idToken: id_token,
      expires: Date.now() + (expires_in * 1000),
      created: Date.now()
    });

    // Set session cookie (HTTP-only, secure, signed)
    res.cookie('session', sessionId, {
      httpOnly: true,
      secure: true,
      sameSite: 'strict',
      signed: true,
      maxAge: 7 * 24 * 60 * 60 * 1000 // 7 days
    });

    // Set CSRF token cookie for SPA
    res.cookie('XSRF-TOKEN', req.csrfToken(), {
      secure: true,
      sameSite: 'strict',
      maxAge: 24 * 60 * 60 * 1000 // 1 day
    });

    // Redirect to SPA with success status
    res.redirect(`${process.env.CLIENT_ORIGIN}/auth-success`);
  } catch (error) {
    console.error('Token exchange error:', error.message);
    res.status(500).json({ error: 'Authentication failed' });
  }
});

// Token refresh endpoint
app.post('/api/auth/refresh', csrfProtection, async (req, res) => {
  // Get session ID from signed cookie
  const sessionId = req.signedCookies.session;
  if (!sessionId) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  // Get stored tokens
  const tokenData = tokenStore.get(sessionId);
  if (!tokenData || !tokenData.refreshToken) {
    return res.status(401).json({ error: 'Invalid session' });
  }

  try {
    // Exchange refresh token for new access token
    const tokenResponse = await axios.post(config.refreshEndpoint, new URLSearchParams({
      grant_type: 'refresh_token',
      client_id: config.clientID,
      client_secret: config.clientSecret,
      refresh_token: tokenData.refreshToken
    }), {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      }
    });

    const { access_token, refresh_token, expires_in } = tokenResponse.data;

    // Update stored tokens
    tokenStore.set(sessionId, {
      ...tokenData,
      accessToken: access_token,
      refreshToken: refresh_token || tokenData.refreshToken, // Some providers don't return a new refresh token
      expires: Date.now() + (expires_in * 1000)
    });

    // Rotate CSRF token
    res.cookie('XSRF-TOKEN', req.csrfToken(), {
      secure: true,
      sameSite: 'strict',
      maxAge: 24 * 60 * 60 * 1000 // 1 day
    });

    res.json({ success: true });
  } catch (error) {
    console.error('Token refresh error:', error.message);
    res.status(401).json({ error: 'Token refresh failed' });
  }
});

// Protected API endpoint example
app.get('/api/protected-resource', csrfProtection, async (req, res) => {
  // Get session ID from signed cookie
  const sessionId = req.signedCookies.session;
  if (!sessionId) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  // Get stored tokens
  const tokenData = tokenStore.get(sessionId);
  if (!tokenData || !tokenData.accessToken) {
    return res.status(401).json({ error: 'Invalid session' });
  }

  // Check if token is expired and needs refresh
  if (tokenData.expires <= Date.now()) {
