// Logout endpoint
app.post('/api/auth/logout', csrfProtection, (req, res) => {
  const sessionId = req.signedCookies.session;

  // Clear session data
  if (sessionId) {
    tokenStore.delete(sessionId);
  }

  // Clear cookies
  res.clearCookie('session');
  res.clearCookie('XSRF-TOKEN');

  res.json({ success: true });
});

