// client.js - SPA OAuth client
class OAuth2Client {
  constructor() {
    this.baseUrl = window.location.origin;
  }

  // Start the OAuth flow
  async login() {
    try {
      const response = await fetch(`${this.baseUrl}/api/auth/login`, {
        credentials: 'include'
      });

      const data = await response.json();
      if (data.authUrl) {
        // Redirect to authorization server
        window.location.href = data.authUrl;
      }
    } catch (error) {
      console.error('Login initialization failed:', error);
      throw new Error('Failed to start authentication flow');
    }
  }

  // Get CSRF token from cookie
  getCsrfToken() {
    return document.cookie
      .split('; ')
      .find(row => row.startsWith('XSRF-TOKEN='))
      ?.split('=')[1];
  }

  // Refresh the access token
  async refreshTokens() {
    try {
      const csrfToken = this.getCsrfToken();
      if (!csrfToken) {
        throw new Error('CSRF token not found');
      }

      const response = await fetch(`${this.baseUrl}/api/auth/refresh`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-CSRF-Token': csrfToken
        },
        credentials: 'include'
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || 'Token refresh failed');
      }

      return true;
    } catch (error) {
      console.error('Token refresh failed:', error);
      this.login(); // Redirect to login if refresh fails
      return false;
    }
  }

  // Make authenticated API request with CSRF protection
  async fetchProtectedResource() {
    try {
      const csrfToken = this.getCsrfToken();
      if (!csrfToken) {
        throw new Error('CSRF token not found');
      }

      const response = await fetch(`${this.baseUrl}/api/protected-resource`, {
        headers: {
          'X-CSRF-Token': csrfToken
        },
        credentials: 'include'
      });

      if (response.ok) {
        return await response.json();
      }

      const error = await response.json();

      // Handle token expiration
      if (error.needsRefresh) {
        const refreshed = await this.refreshTokens();
        if (refreshed) {
          // Retry the request with new tokens
          return await this.fetchProtectedResource();
        }
      }

      throw new Error(error.error || 'Request failed');
    } catch (error) {
      console.error('Protected resource fetch failed:', error);
      throw error;
    }
  }

  // Logout and clear session
  async logout() {
    try {
      const csrfToken = this.getCsrfToken();
      if (!csrfToken) {
        throw new Error('CSRF token not found');
      }

      await fetch(`${this.baseUrl}/api/auth/logout`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-CSRF-Token': csrfToken
        },
        credentials: 'include'
      });

      // Redirect to home page
      window.location.href = '/';
    } catch (error) {
      console.error('Logout failed:', error);
    }
  }
}

// Token rotation schedule (client-side)
class TokenManager {
  constructor(oauthClient) {
    this.oauthClient = oauthClient;
    this.refreshTimer = null;
  }

  // Start token rotation schedule
  startTokenRotation() {
    // Refresh tokens 5 minutes before expiry
    this.refreshTimer = setInterval(() => {
      this.oauthClient.refreshTokens()
        .catch(error => console.error('Scheduled token refresh failed:', error));
    }, 55 * 60 * 1000); // Every 55 minutes (assuming 1-hour token lifetime)
  }

  // Stop token rotation
  stopTokenRotation() {
    if (this.refreshTimer) {
      clearInterval(this.refreshTimer);
      this.refreshTimer = null;
    }
  }
}

