import logging

def create_user_blueprint(user_service: UserService) -> Blueprint:
    """Create Blueprint for user routes."""
    user_bp = Blueprint('user_bp', __name__)

    @user_bp.route('/users/<int:user_id>', methods=['GET'])
    def get_user(user_id: int) -> Any:
        logging.info(f'Retrieving user with id: {user_id}')
        return user_service.get_user(user_id)

    @user_bp.route('/users', methods=['GET'])
    def get_all_users() -> Any:
        logging.info('Retrieving all users')
        users = user_service.get_all()
        return jsonify([user.to_dict() for user in users])

    @user_bp.route('/users', methods=['POST'])
    def create_user() -> Any:
        logging.info('Creating a new user')
        return user_service.create_user()

    @user_bp.route('/users/<int:user_id>', methods=['PUT'])
    def update_user(user_id: int) -> Any:
        logging.info(f'Updating user with id: {user_id}')
        data = request.get_json()
        user = user_service.update(user_id, data)
        if user:
            return jsonify(user.to_dict())
        return jsonify({'error': 'User not found'}), 404

    @user_bp.route('/users/<int:user_id>', methods=['DELETE'])
    def delete_user(user_id: int) -> Any:
        logging.info(f'Deleting user with id: {user_id}')
        success = user_service.delete(user_id)
        if success:
            return jsonify({'message': 'User deleted successfully'})
        return jsonify({'error': 'User not found'}), 404

    return user_bp

