class KafkaEventProcessorTest {

    @Mock
    private IKafkaConsumerWrapper mockConsumerWrapper;

    private KafkaEventProcessor processor;
    private final String topicName = "test-topic";

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
        processor = new KafkaEventProcessor(mockConsumerWrapper, topicName);
    }

    @Test
    void testProcessEventDirectly() {
        // Test direct event processing
        processor.processEvent("test-event");
        // This would normally verify some processing logic, but since it's just printing,
        // we verify the method can be called without exception
    }

    @Test
    void testStartAndStopProcessor() throws InterruptedException {
        // Mock empty records to avoid infinite loop
        ConsumerRecords<String, String> emptyRecords = new ConsumerRecords<>(Collections.emptyMap());
        when(mockConsumerWrapper.poll(any(Duration.class))).thenReturn(emptyRecords);

        processor.start();
        Thread.sleep(200); // Let it run briefly
        processor.stop();

        verify(mockConsumerWrapper).subscribe(Collections.singletonList(topicName));
        verify(mockConsumerWrapper, atLeastOnce()).poll(Duration.ofMillis(100));
        verify(mockConsumerWrapper, atLeastOnce()).close();
    }

