        processor.stop();

        verify(mockConsumerWrapper).subscribe(Collections.singletonList(topicName));
        verify(mockConsumerWrapper, atLeastOnce()).poll(Duration.ofMillis(100));
        verify(mockConsumerWrapper, atLeast(1)).commitSync();
        verify(mockConsumerWrapper, atLeastOnce()).close();
    }
}

