  description?: string;
  required?: string[];
  title?: string;
  enum?: any[];
  format?: string;
  minimum?: number;
  maximum?: number;
  minLength?: number;
  maxLength?: number;
}

interface ValidationError {
  path: string;
  message: string;
}

