    const errors: ValidationError[] = [];

    const validateRecursive = (obj: JSONSchema, path: string) => {
      if (!obj.type) {
        errors.push({ path, message: 'Type is required' });
      }

      if (obj.type === 'object' && obj.properties) {
        Object.entries(obj.properties).forEach(([key, value]) => {
          if (!key.trim()) {
            errors.push({ path: `${path}.${key}`, message: 'Property name cannot be empty' });
          }
          validateRecursive(value, `${path}.${key}`);
        });
      }

      if (obj.type === 'array' && obj.items) {
        validateRecursive(obj.items, `${path}.items`);
      }

      if (obj.minimum !== undefined && obj.maximum !== undefined && obj.minimum > obj.maximum) {
        errors.push({ path, message: 'Minimum cannot be greater than maximum' });
      }

      if (obj.minLength !== undefined && obj.maxLength !== undefined && obj.minLength > obj.maxLength) {
        errors.push({ path, message: 'Minimum length cannot be greater than maximum length' });
