// Middleware chain helper
type Middleware func(http.Handler) http.Handler

func chainMiddleware(middlewares ...Middleware) http.Handler {
	var handler http.Handler = http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// This will be overridden by the chain
	})

	// Apply middleware in reverse order (last middleware specified is outermost)
	for i := len(middlewares) - 1; i >= 0; i-- {
		handler = middlewares[i](handler)
	}

	return handler
}

// Security headers middleware
func securityHeadersMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Set security headers
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("Content-Security-Policy", "default-src 'none'; frame-ancestors 'none'")
		w.Header().Set("X-XSS-Protection", "1; mode=block")
		w.Header().Set("Referrer-Policy", "no-referrer")
		w.Header().Set("Cache-Control", "no-store")
		w.Header().Set("Pragma", "no-cache")
		next.ServeHTTP(w, r)
	})
}

// TLS enforcement middleware
func tlsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Ensure connection is secure
		if r.TLS == nil {
			w.Header().Set("Strict-Transport-Security", "max-age=63072000; includeSubDomains; preload")
			logAudit("tls_enforcement", "anonymous", r.URL.Path, r, false, "TLS required but not used")
			respondWithError(w, "invalid_request", "TLS connection required", http.StatusBadRequest)
			return
		}
		next.ServeHTTP(w, r)
	})
}

// Rate limiting middleware with per-IP limits
func rateLimitMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		ip := getClientIP(r)

		mu.Lock()
		if _, exists := limiter[ip]; !exists {
			limiter[ip] = rate.NewLimiter(rate.Limit(config.RateLimitRequests)/config.RateLimitPeriod.Minutes(), config.RateLimitRequests)
		}
		ratelimiter := limiter[ip]
		mu.Unlock()

		if !ratelimiter.Allow() {
			logAudit("rate_limit_exceeded", "anonymous", r.URL.Path, r, false, "Rate limit exceeded from IP: "+ip)
			respondWithError(w, "too_many_requests", "Rate limit exceeded", http.StatusTooManyRequests)
			return
		}
		next.ServeHTTP(w, r)
	})
}

