// Initialize database connection and schema
func initDB() {
	var err error

	// Connect to database
	db, err = sqlx.Connect("mysql", config.DSN)
	if err != nil {
		logger.Fatalf("Could not connect to database: %v", err)
	}

	// Configure connection pool
	db.SetMaxOpenConns(25)
	db.SetMaxIdleConns(5)
	db.SetConnMaxLifetime(5 * time.Minute)

	// Initialize tables with proper constraints and indexes
	initSchema := `
	CREATE TABLE IF NOT EXISTS clients (
		id VARCHAR(255) PRIMARY KEY,
		secret VARCHAR(255) NOT NULL,
		redirect_uris TEXT NOT NULL,
		created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
	);

	CREATE TABLE IF NOT EXISTS auth_requests (
		state VARCHAR(255) NOT NULL,
		code_challenge VARCHAR(255) NOT NULL,
		code_challenge_method VARCHAR(20) NOT NULL,
		client_id VARCHAR(255) NOT NULL,
		redirect_uri VARCHAR(255) NOT NULL,
		scope VARCHAR(255) NOT NULL,
		code VARCHAR(255) NOT NULL PRIMARY KEY,
		expires_at TIMESTAMP NOT NULL,
		used BOOLEAN DEFAULT FALSE,
		user_id VARCHAR(255) NOT NULL,
		INDEX (expires_at),
		INDEX (client_id, code)
	);

	CREATE TABLE IF NOT EXISTS tokens (
		access_token VARCHAR(2048) PRIMARY KEY,
		refresh_token VARCHAR(2048) UNIQUE,
		token_type VARCHAR(20) NOT NULL,
		expires_in INT NOT NULL,
		scope VARCHAR(255) NOT NULL,
		user_id VARCHAR(255) NOT NULL,
		client_id VARCHAR(255) NOT NULL,
		expires_at TIMESTAMP NOT NULL,
		revoked BOOLEAN DEFAULT FALSE,
		INDEX (client_id),
		INDEX (expires_at),
		INDEX (refresh_token)
	);

	CREATE TABLE IF NOT EXISTS audit_logs (
		id BIGINT AUTO_INCREMENT PRIMARY KEY,
		action VARCHAR(50) NOT NULL,
		actor VARCHAR(255) NOT NULL,
		resource VARCHAR(255) NOT NULL,
		timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
		ip VARCHAR(45) NOT NULL,
		user_agent VARCHAR(255) NOT NULL,
		success BOOLEAN NOT NULL,
		details TEXT,
		INDEX (timestamp),
		INDEX (action),
		INDEX (actor)
	);`

	_, err = db.Exec(initSchema)
	if err != nil {
		logger.Fatalf("Could not initialize database schema: %v", err)
	}

	// Verify connection works
	err = db.Ping()
	if err != nil {
		logger.Fatalf("Database connection failed: %v", err)
	}

	logger.Println("Database initialized successfully")
}

// Security headers middleware
func securityHeadersMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Set security headers
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("Content-Security-Policy", "default-src 'none'; frame-ancestors 'none'")
		w.Header().Set("X-XSS-Protection", "1; mode=block")
		w.Header().Set("Referrer-Policy", "no-referrer")
		w.Header().Set("Cache-Control", "no-store")
		w.Header().Set("Pragma", "no-cache")
		w.Header().Set("Strict-Transport-Security", "max-age=63072000; includeSubDomains; preload")
		next.ServeHTTP(w, r)
	})
}

// TLS enforcement middleware
func forceTLSMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Ensure connection is secure
		if r.TLS == nil && r.Header.Get("X-Forwarded-Proto") != "https" {
			logAudit("tls_enforcement", "anonymous", r.URL.Path, r, false, "TLS required but not used")
			respondWithError(w, "invalid_request", "HTTPS connection required", http.StatusBadRequest)
			return
		}
		next.ServeHTTP(w, r)
	})
}

// OAuth authorization endpoint handler
func authHandler(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
	defer cancel()
	r = r.WithContext(ctx)

	// Extract and validate required parameters
	clientID := r.URL.Query().Get("client_id")
	redirectURI := r.URL.Query().Get("redirect_uri")
	state := r.URL.Query().Get("state")
	responseType := r.URL.Query().Get("response_type")
	scope := r.URL.Query().Get("scope")
	codeChallenge := r.URL.Query().Get("code_challenge")
	codeChallengeMethod := r.URL.Query().Get("code_challenge_method")

	// Validate all required parameters
	if clientID == "" || redirectURI == "" || state == "" || responseType != "code" {
		logAudit("authorize_request", clientID, "authorization", r, false, "Invalid request parameters")
		respondWithError(w, "invalid_request", "Missing required parameters", http.StatusBadRequest)
		return
	}

	// PKCE is required for security
	if codeChallenge == "" || codeChallengeMethod == "" {
		logAudit("authorize_request", clientID, "authorization", r, false, "PKCE parameters missing")
		respondWithError(w, "invalid_request", "PKCE is required", http.StatusBadRequest)
		return
	}

	// Only S256 is supported to ensure security
	if codeChallengeMethod != "S256" {
		logAudit("authorize_request", clientID, "authorization", r, false, "Unsupported code challenge method")
		respondWithError(w, "invalid_request", "Only S256 code challenge method is supported", http.StatusBadRequest)
		return
	}

	// Validate client exists in database
	var client Client
	err := db.GetContext(ctx, &client, "SELECT * FROM clients WHERE id = ?", clientID)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			logAudit("authorize_request", clientID, "authorization", r, false, "Invalid client ID")
			respondWithError(w, "invalid_client", "Invalid client", http.StatusBadRequest)
			return
		}
		logAudit("authorize_request", clientID, "authorization", r, false, fmt.Sprintf("Database error: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Validate redirect URI against registered URIs
	validURIs := strings.Split(client.RedirectURIs, ",")
	validRedirect := false
	for _, uri := range validURIs {
		if uri == redirectURI {
			validRedirect = true
			break
		}
	}

	if !validRedirect {
		logAudit("authorize_request", clientID, "authorization", r, false, "Invalid redirect URI")
		respondWithError(w, "invalid_request", "Invalid redirect URI", http.StatusBadRequest)
		return
	}

	// In a real app, user authentication would happen here
	// For this example, we assume the user is authenticated with ID "user123"
	userID := "user123"

	// Generate secure authorization code
	code, err := generateSecureRandomString(32)
	if err != nil {
		logAudit("authorize_request", clientID, "authorization", r, false, fmt.Sprintf("Error generating code: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Save auth request with all security parameters
	authRequest := AuthRequest{
		State:               state,
		CodeChallenge:       codeChallenge,
		CodeChallengeMethod: codeChallengeMethod,
		ClientID:            clientID,
		RedirectURI:         redirectURI,
		Scope:               scope,
		Code:                code,
		ExpiresAt:           time.Now().Add(config.CodeExpiryDuration),
		Used:                false,
		UserID:              userID,
	}

	// Insert auth request into database
	_, err = db.NamedExecContext(ctx, `
		INSERT INTO auth_requests (
			state, code_challenge, code_challenge_method, client_id, redirect_uri, 
			scope, code, expires_at, used, user_id
		) VALUES (
			:state, :code_challenge, :code_challenge_method, :client_id, :redirect_uri,
			:scope, :code, :expires_at, :used, :user_id
		)`, authRequest)

	if err != nil {
		logAudit("authorize_request", clientID, "authorization", r, false, fmt.Sprintf("Error saving auth request: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Redirect with code and state parameters
	redirectURL := fmt.Sprintf("%s?code=%s&state=%s", redirectURI, code, state)
	logAudit("authorize_request", clientID, "authorization", r, true, fmt.Sprintf("Authorization granted for user %s", userID))
	http.Redirect(w, r, redirectURL, http.StatusFound)
}

// OAuth token endpoint handler
func tokenHandler(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
	defer cancel()
	r = r.WithContext(ctx)

	// Parse form data
	err := r.ParseForm()
	if err != nil {
		logAudit("token_request", "anonymous", "token", r, false, "Error parsing form")
		respondWithError(w, "invalid_request", "Invalid request format", http.StatusBadRequest)
		return
	}

	// Extract and validate required parameters
	grantType := r.Form.Get("grant_type")
	code := r.Form.Get("code")
	redirectURI := r.Form.Get("redirect_uri")
	clientID := r.Form.Get("client_id")
	codeVerifier := r.Form.Get("code_verifier")

	// Validate parameters are present
	if grantType != "authorization_code" || code == "" || redirectURI == "" || clientID == "" || codeVerifier == "" {
		logAudit("token_request", clientID, "token", r, false, "Invalid or missing request parameters")
		respondWithError(w, "invalid_request", "Missing or invalid parameters", http.StatusBadRequest)
		return
	}

	// Validate code exists and is valid
	var authRequest AuthRequest
	err = db.GetContext(ctx, &authRequest, `
		SELECT * FROM auth_requests 
		WHERE code = ? AND client_id = ? AND expires_at > ? AND used = false`, 
		code, clientID, time.Now())

	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			logAudit("token_request", clientID, "token", r, false, "Invalid, expired, or used code")
			respondWithError(w, "invalid_grant", "Invalid authorization code", http.StatusBadRequest)
			return
		}
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Database error: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Validate redirect URI matches the one used in authorization request
	if authRequest.RedirectURI != redirectURI {
		logAudit("token_request", clientID, "token", r, false, "Redirect URI mismatch")
		respondWithError(w, "invalid_grant", "Redirect URI doesn't match authorization request", http.StatusBadRequest)
		return
	}

	// Validate code verifier with PKCE
	h := sha256.New()
	h.Write([]byte(codeVerifier))
	calculatedChallenge := base64.RawURLEncoding.EncodeToString(h.Sum(nil))

	if calculatedChallenge != authRequest.CodeChallenge {
		logAudit("token_request", clientID, "token", r, false, "Code verifier doesn't match challenge")
		respondWithError(w, "invalid_grant", "Invalid code verifier", http.StatusBadRequest)
		return
	}

	// Mark code as used to prevent replay attacks - using a transaction for atomicity
	tx, err := db.BeginTxx(ctx, nil)
	if err != nil {
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Transaction error: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Update code to mark as used
	result, err := tx.ExecContext(ctx, "UPDATE auth_requests SET used = true WHERE code = ? AND used = false", code)
	if err != nil {
		tx.Rollback()
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Database error: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Check if update was successful (to handle race conditions)
	rowsAffected, err := result.RowsAffected()
	if err != nil || rowsAffected == 0 {
		tx.Rollback()
		logAudit("token_request", clientID, "token", r, false, "Code already used or invalid")
		respondWithError(w, "invalid_grant", "Code already used", http.StatusBadRequest)
		return
	}

	// Generate secure tokens
	accessToken, refreshToken, err := generateTokens(authRequest.UserID, clientID, authRequest.Scope)
	if err != nil {
		tx.Rollback()
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Error generating tokens: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Create token with proper expiration
	expiresIn := int(config.TokenExpiryDuration.Seconds())
	token := Token{
		AccessToken:  accessToken,
		RefreshToken: refreshToken,
		TokenType:    "Bearer",
		ExpiresIn:    expiresIn,
		Scope:        authRequest.Scope,
		UserID:       authRequest.UserID,
		ClientID:     clientID,
		ExpiresAt:    time.Now().Add(config.TokenExpiryDuration),
		Revoked:      false,
	}

	// Save token to database within the transaction
	_, err = tx.NamedExecContext(ctx, `
		INSERT INTO tokens (
			access_token, refresh_token, token_type, expires_in, 
			scope, user_id, client_id, expires_at, revoked
		) VALUES (
			:access_token, :refresh_token, :token_type, :expires_in,
			:scope, :user_id, :client_id, :expires_at, :revoked
		)`, token)

	if err != nil {
		tx.Rollback()
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Error saving token: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Commit transaction
	if err := tx.Commit(); err != nil {
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Transaction commit error: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Prepare response
	tokenResponse := TokenResponse{
		AccessToken:  token.AccessToken,
		RefreshToken: token.RefreshToken,
		TokenType:    token.TokenType,
		ExpiresIn:    token.ExpiresIn,
		Scope:        token.Scope,
	}

	// Return token response
	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Cache-Control", "no-store")
	w.Header().Set("Pragma", "no-cache")

	err = json.NewEncoder(w).Encode(tokenResponse)
	if err != nil {
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Error encoding response: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	logAudit("token_request", clientID, "token", r, true, fmt.Sprintf("Tokens issued for user %s", authRequest.UserID))
}

// Token revocation endpoint handler
func revokeHandler(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
	defer cancel()
	r = r.WithContext(ctx)

	// Parse form data
	err := r.ParseForm()
	if err != nil {
		logAudit("revoke_request", "anonymous", "token", r, false, "Error parsing form")
		respondWithError(w, "invalid_request", "Invalid request format", http.StatusBadRequest)
		return
	}

	// Extract required parameters
	token := r.Form.Get("token")
	tokenTypeHint := r.Form.Get("token_type_hint")
	clientID := r.Form.Get("client_id")

	// Validate required parameters
	if token == "" || clientID == "" {
		logAudit("revoke_request", clientID, "token", r, false, "Missing token or client_id")
		respondWithError(w, "invalid_request", "Missing required parameters", http.StatusBadRequest)
		return
	}

	// Find the token record based on token type hint
	var tokenRecord Token
	var query string
	var args []interface{}

	// Use token type hint to optimize the query if provided
	if tokenTypeHint == "access_token" {
		query = "SELECT * FROM tokens WHERE access_token = ? AND client_id = ?"
		args = []interface{}{token, clientID}
	} else if tokenTypeHint == "refresh_token" {
		query = "SELECT * FROM tokens WHERE refresh_token = ? AND client_id = ?"
		args = []interface{}{token, clientID}
	} else {
		// Try both if hint not provided or invalid
		query = "SELECT * FROM tokens WHERE (access_token = ? OR refresh_token = ?) AND client_id = ?"
		args = []interface{}{token, token, clientID}
	}

	// Retrieve token record
	err = db.GetContext(ctx, &tokenRecord, query, args...)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			// Per OAuth 2.0 spec, still return success for non-existent tokens
			w.WriteHeader(http.StatusOK)
			logAudit("revoke_request", clientID, "token", r, false, "Token not found but returning OK per spec")
			return
		}
		logAudit("revoke_request", clientID, "token", r, false, fmt.Sprintf("Database error: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Revoke token in transaction to ensure atomicity
	tx, err := db.BeginTxx(ctx, nil)
	if err != nil {
		logAudit("revoke_request", clientID, "token", r, false, fmt.Sprintf("Transaction error: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Revoke both access and refresh tokens for complete revocation
	_, err = tx.ExecContext(ctx, 
		"UPDATE tokens SET revoked = true WHERE access_token = ? OR refresh_token = ?", 
		tokenRecord.AccessToken, tokenRecord.RefreshToken)

	if err != nil {
		tx.Rollback()
		logAudit("revoke_request", clientID, "token", r, false, fmt.Sprintf("Database error: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Commit transaction
	if err := tx.Commit(); err != nil {
		logAudit("revoke_request", clientID, "token", r, false, fmt.Sprintf("Transaction commit error: %v", err))
		respondWithError(w, "server_error", "Internal server error", http.StatusInternalServerError)
		return
	}

	// Return success response
	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Cache-Control", "no-store")
	w.Header().Set("Pragma", "no-cache")
	w.WriteHeader(http.StatusOK)

	// Return simple success response
	err = json.NewEncoder(w).Encode(map[string]bool{"revoked": true})
	if err != nil {
		logger.Printf("Error encoding revoke response: %v", err)
	}

	logAudit("revoke_request", clientID, "token", r, true, "Token revoked successfully")
}

// Generate secure random string of specified length
func generateSecureRandomString(length int) (string, error) {
	b := make([]byte, length)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return base64.RawURLEncoding.EncodeToString(b), nil
}

// Generate secure JWT access and refresh tokens
func generateTokens(userID, clientID, scope string) (string, string, error) {
	// Generate unique JTI (JWT ID) for tokens
	accessJTI, err := generateSecureRandomString(16)
	if err != nil {
		return "", "", err
	}

	refreshJTI, err := generateSecureRandomString(16)
	if err != nil {
		return "", "", err
	}

	// Create access token with security claims
	accessTokenClaims := jwt.MapClaims{
		"sub":   userID,
		"aud":   clientID,
		"scope": scope,
		"exp":   time.Now().Add(config.TokenExpiryDuration).Unix(),
		"iat":   time.Now().Unix(),
		"jti":   accessJTI,
		"nbf":   time.Now().Unix(), // Not before - prevents token reuse before intended time
	}

	accessToken := jwt.NewWithClaims(jwt.SigningMethodHS256, accessTokenClaims)
	accessTokenSigned, err := accessToken.SignedString(config.JWTSecret)
	if err != nil {
		return "", "", err
	}

	// Create refresh token with longer expiry
	refreshTokenClaims := jwt.MapClaims{
		"sub":   userID,
		"aud":   clientID,
		"exp":   time.Now().Add(30 * 24 * time.Hour).Unix(), // 30 days
		"iat":   time.Now().Unix(),
		"jti":   refreshJTI,
		"nbf":   time.Now().Unix(),
	}

	refreshToken := jwt.NewWithClaims(jwt.SigningMethodHS256, refreshTokenClaims)
	refreshTokenSigned, err := refreshToken.SignedString(config.JWTSecret)
	if err != nil {
		return "", "", err
	}

	return accessTokenSigned, refreshTokenSigned, nil
}

// Get client IP with X-Forwarded-For support
func getClientIP(r *http.Request) string {
	// Check for X-Forwarded-For header first (for proxies)
	forwardedFor := r.Header.Get("X-Forwarded-For")
	if forwardedFor != "" {
		// Only use the leftmost IP (client IP) to prevent spoofing
		return strings.TrimSpace(strings.Split(forwardedFor, ",")[0])
	}

	// Fall back to RemoteAddr if no X-Forwarded-For
	return strings.Split(r.RemoteAddr, ":")[0]
}

// Log audit events to database
func logAudit(action, actor, resource string, r *http.Request, success bool, details string) {
	// Create audit log entry
	auditLog := AuditLog{
		Action:    action,
		Actor:     actor,
		Resource:  resource,
		Timestamp: time.Now(),
		IP:        getClientIP(r),
		UserAgent: r.UserAgent(),
		Success:   success,
		Details:   details,
	}

	// Insert audit log asynchronously to not block request processing
	go func(log AuditLog) {
		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()

		_, err := db.NamedExecContext(ctx, `
			INSERT INTO audit_logs (
				action, actor, resource, timestamp, ip, user_agent, success, details
			) VALUES (
				:action, :actor, :resource, :timestamp, :ip, :user_agent, :success, :details
			)`, log)

		if err != nil {
			logger.Printf("Failed to log audit: %v", err)
		}
	}(auditLog)

	// Also log to standard logger
	if success {
		logger.Printf("[AUDIT] %s by %s on %s: %s", action, actor, resource, details)
	} else {
		logger.Printf("[AUDIT-FAIL] %s by %s on %s: %s", action, actor, resource, details)
	}
}

// Standard error response formatter
func respondWithError(w http.ResponseWriter, error string, description string, statusCode int) {
	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Cache-Control", "no-store")
	w.Header().Set("Pragma", "no-cache")
	w.WriteHeader(statusCode)

	errorResponse := ErrorResponse{
		Error:       error,
		Description: description,
	}

	json.NewEncoder(w).Encode(errorResponse)
}

