from abc import ABC, abstractmethod
import importlib
import pkgutil
from typing import Dict, Tuple, List, Any, Type
import heapq

class GraphSearch(ABC):
    @abstractmethod
    def search(self, start: Any, goal: Any) -> List[Any]:
        """Perform the search and return the path from start to goal as a list."""
        pass

class Graph(ABC):
    @abstractmethod
    def get_neighbors(self, node: Any) -> List[Any]:
        """Return the list of neighbors for a given node."""
        pass

    @abstractmethod
    def cost(self, current: Any, neighbor: Any) -> float:
        """Return the cost of moving from the current node to a neighbor."""
        pass

    @abstractmethod
    def heuristic(self, current: Any, goal: Any) -> float:
        """Return the heuristic estimate of the cost from current node to the goal."""
        pass


