// sendHeartbeats sends AppendEntries RPCs to all peers (may be empty as heartbeats)
func (s *RaftServer) sendHeartbeats() {
	s.mu.Lock()
	term := s.currentTerm
	s.mu.Unlock()

	for _, peer := range s.peers {
		if s.isPartitioned(peer) {
			continue // Skip if there's a network partition
		}

		go func(peer int) {
			s.mu.Lock()
			prevLogIndex := s.nextIndex[peer] - 1
			prevLogTerm := 0
			if prevLogIndex >= 0 && prevLogIndex < len(s.log) {
				prevLogTerm = s.log[prevLogIndex].Term
			}

			entries := []LogEntry{}
			if s.nextIndex[peer] < len(s.log) {
				entries = s.log[s.nextIndex[peer]:]
			}

			args := AppendEntriesArgs{
				Term:         s.currentTerm,
				LeaderID:     s.id,
				PrevLogIndex: prevLogIndex,
				PrevLogTerm:  prevLogTerm,
				Entries:      entries,
				LeaderCommit: s.commitIndex,
			}
			s.mu.Unlock()

			s.appendEntriesCh[peer] <- args
		}(peer)
	}
}

// listenForRequestVote handles incoming RequestVote RPCs
