			continue
		}

		if s.state == Candidate && reply.Term == s.currentTerm {
			s.voteResponses <- reply.VoteGranted
		}

		s.mu.Unlock()
	}
}

// listenForAppendEntries handles incoming AppendEntries RPCs
func (s *RaftServer) listenForAppendEntries(peer int) {
	for args := range s.appendEntriesCh[peer] {
		s.mu.Lock()

		reply := AppendEntriesReply{
			Term:    s.currentTerm,
			Success: false,
		}

		if args.Term < s.currentTerm {
			// Reply false if term < currentTerm
			s.mu.Unlock()
			if !s.isPartitioned(peer) {
				s.appendEntriesRespCh[peer] <- reply
			}
			continue
		}

		// If AppendEntries RPC received from new leader: convert to follower
		if args.Term >= s.currentTerm {
			if args.Term > s.currentTerm {
				s.currentTerm = args.Term
				s.votedFor = -1
			}

			s.state = Follower
			s.leader = args.LeaderID
			select {
			case s.heartbeatReset <- true:
			default:
			}
		}

		// Reply false if log doesn't contain an entry at prevLogIndex whose term matches prevLogTerm
		if args.PrevLogIndex >= len(s.log) || 
			(args.PrevLogIndex >= 0 && s.log[args.PrevLogIndex].Term != args.PrevLogTerm) {
			if args.PrevLogIndex >= len(s.log) {
				reply.NextIndex = len(s.log)
			} else {
				// Find the first index of the conflicting term
				term := s.log[args.PrevLogIndex].Term
				index := args.PrevLogIndex
				for index > 0 && s.log[index-1].Term == term {
					index--
				}
				reply.NextIndex = index
			}
			s.mu.Unlock()
			if !s.isPartitioned(peer) {
				s.appendEntriesRespCh[peer] <- reply
			}
			continue
		}

		// If an existing entry conflicts with a new one (same index but different terms),
		// delete the existing entry and all that follow it
		newEntries := make([]LogEntry, 0)
		newEntriesIndex := 0

		for i := args.PrevLogIndex + 1; i < len(s.log) && newEntriesIndex < len(args.Entries); i++ {
			if i >= len(s.log) || s.log[i].Term != args.Entries[newEntriesIndex].Term {
				s.log = s.log[:i]
				break
			}
			newEntriesIndex++
		}

		// Append any new entries not already in the log
		if newEntriesIndex < len(args.Entries) {
			newEntries = args.Entries[newEntriesIndex:]
			s.log = append(s.log, newEntries...)
			s.logger.Printf("Server %d: appended %d new entries from leader %d\n", s.id, len(newEntries), args.LeaderID)
		}

		// Update commit index if leaderCommit > commitIndex
		if args.LeaderCommit > s.commitIndex {
			s.commitIndex = min(args.LeaderCommit, len(s.log)-1)
			s.applyCommittedEntries()
		}

		reply.Success = true
		reply.NextIndex = len(s.log)

		s.mu.Unlock()

		if !s.isPartitioned(peer) {
			s.appendEntriesRespCh[peer] <- reply
		}
	}
}

// listenForAppendEntriesResponse handles responses to AppendEntries RPCs
func (s *RaftServer) listenForAppendEntriesResponse(peer int) {
	for reply := range s.appendEntriesRespCh[peer] {
		s.mu.Lock()

		if reply.Term > s.currentTerm {
			// If RPC response contains term T > currentTerm: set currentTerm = T, convert to follower
			s.currentTerm = reply.Term
			s.state = Follower
			s.votedFor = -1
			s.leader = -1
			s.mu.Unlock()
			continue
		}

		if s.state == Leader && reply.Term == s.currentTerm {
			if reply.Success {
				// Update nextIndex and matchIndex for follower
				s.matchIndex[peer] = reply.NextIndex - 1
				s.nextIndex[peer] = reply.NextIndex

				// Check if we can commit any entries
				s.updateCommitIndex()
			} else {
				// Decrement nextIndex and retry
				s.nextIndex[peer] = reply.NextIndex
				s.logger.Printf("Server %d: AppendEntries to %d failed, setting nextIndex=%d\n", s.id, peer, s.nextIndex[peer])
			}
		}

		s.mu.Unlock()
	}
}

// updateCommitIndex checks if we can commit any entries
func (s *RaftServer) updateCommitIndex() {
	// Find the highest matchIndex that is replicated on a majority of servers
	for n := s.commitIndex + 1; n < len(s.log); n++ {
		if s.log[n].Term != s.currentTerm {
			continue
		}

		count := 1 // Leader has the entry
		for _, peer := range s.peers {
			if s.matchIndex[peer] >= n {
				count++
			}
		}

		if count > (len(s.peers)+1)/2 {
			s.commitIndex = n
			s.applyCommittedEntries()
		}
	}
}

// applyCommittedEntries applies all committed but not yet applied log entries
func (s *RaftServer) applyCommittedEntries() {
	for s.lastApplied < s.commitIndex {
		s.lastApplied++
		entry := s.log[s.lastApplied]
		s.logger.Printf("Server %d: applying command %s from term %d\n", s.id, entry.Command, entry.Term)
		// In a real implementation, we would apply the command to the state machine here
	}
}

// AppendCommand adds a command to the log (client API)
func (s *RaftServer) AppendCommand(command string) bool {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.state != Leader {
		return false
	}

	// Append to leader's log
	entry := LogEntry{
		Term:    s.currentTerm,
		Command: command,
	}
	s.log = append(s.log, entry)
	s.matchIndex[s.id] = len(s.log) - 1
	s.logger.Printf("Server %d: received new command: %s\n", s.id, command)

	return true
}

// Crash simulates a server crash
func (s *RaftServer) Crash() {
	s.mu.Lock()
	defer s.mu.Unlock()

	if !s.isActive {
		return
	}

	s.logger.Printf("Server %d: CRASHED\n", s.id)
	s.isActive = false
}

// Restart simulates a server restart
func (s *RaftServer) Restart() {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.isActive {
		return
	}

	s.logger.Printf("Server %d: RESTARTED\n", s.id)
	s.isActive = true
	s.state = Follower
	s.leader = -1
	s.resetElectionTimeout()
}

// CreatePartition creates a network partition between this server and peer
func (s *RaftServer) CreatePartition(peer int) {
	s.mu.Lock()
	defer s.mu.Unlock()

	s.partition[peer] = true
	s.logger.Printf("Server %d: NETWORK PARTITION with %d created\n", s.id, peer)
}

// HealPartition heals a network partition between this server and peer
func (s *RaftServer) HealPartition(peer int) {
	s.mu.Lock()
	defer s.mu.Unlock()

	s.partition[peer] = false
	s.logger.Printf("Server %d: NETWORK PARTITION with %d healed\n", s.id, peer)
}

// GetState returns the server's current state
func (s *RaftServer) GetState() (int, int, int, bool) {
	s.mu.Lock()
	defer s.mu.Unlock()

	return s.state, s.currentTerm, s.commitIndex, s.isActive
}

// CreateCluster creates a new Raft cluster with the specified number of servers
func CreateCluster(numServers int) *Cluster {
	logFile, err := os.Create("raft_simulation.log")
	if err != nil {
		panic(err)
	}

	logger := log.New(logFile, "", log.Ldate|log.Ltime|log.Lmicroseconds)
	logger.Println("Starting Raft cluster simulation")

	servers := make([]*RaftServer, numServers)

	// Create all server IDs
	serverIDs := make([]int, numServers)
	for i := 0; i < numServers; i++ {
		serverIDs[i] = i
	}

	// Create and start each server
	for i := 0; i < numServers; i++ {
		peers := make([]int, 0)
		for j := 0; j < numServers; j++ {
			if j != i {
				peers = append(peers, j)
			}
		}

		servers[i] = NewRaftServer(i, peers, logger)
		servers[i].Start()
	}

	return &Cluster{
		servers: servers,
		logger:  logger,
	}
}

// RunFaultInjectionTests runs a series of fault injection tests on the cluster
func (c *Cluster) RunFaultInjectionTests() {
	c.logger.Println("Starting fault injection tests")

	// Wait for a leader to be elected
	time.Sleep(1 * time.Second)

	// Find the current leader
	leader := c.findCurrentLeader()
	if leader == -1 {
		c.logger.Println("No leader elected, extending timeout")
		time.Sleep(2 * time.Second)
		leader = c.findCurrentLeader()
	}

	if leader == -1 {
		c.logger.Println("Failed to elect a leader, aborting tests")
		return
	}

	c.logger.Printf("Initial leader is Server %d\n", leader)

	// Test 1: Add some commands
	c.logger.Println("TEST 1: Adding commands to stable cluster")
	for i := 0; i < 5; i++ {
		cmd := fmt.Sprintf("command-%d", i)
		if !c.servers[leader].AppendCommand(cmd) {
			c.logger.Printf("Failed to append command %s\n", cmd)
		}
		time.Sleep(100 * time.Millisecond)
	}

	// Test 2: Crash the leader
	c.logger.Println("TEST 2: Crashing the leader")
	c.servers[leader].Crash()

	// Wait for a new leader to be elected
	time.Sleep(2 * time.Second)

	// Find the new leader
	newLeader := c.findCurrentLeader()
	if newLeader != -1 {
		c.logger.Printf("New leader is Server %d\n", newLeader)

		// Add some more commands
		c.logger.Println("TEST 3: Adding commands after leader failure")
		for i := 5; i < 10; i++ {
			cmd := fmt.Sprintf("command-%d", i)
			if !c.servers[newLeader].AppendCommand(cmd) {
				c.logger.Printf("Failed to append command %s\n", cmd)
			}
			time.Sleep(100 * time.Millisecond)
		}
	} else {
		c.logger.Println("No new leader elected after crash")
	}

	// Test 3: Restart the crashed leader
	c.logger.Println("TEST 4: Restarting the crashed leader")
	c.servers[leader].Restart()
	time.Sleep(1 * time.Second)

	// Test 4: Create a network partition
	if newLeader != -1 {
		c.logger.Println("TEST 5: Creating network partition")
		// Partition the cluster so the new leader is isolated
		partitionedServers := []int{newLeader}
		for i := 0; i < len(c.servers); i++ {
			if i != newLeader {
				c.servers[newLeader].CreatePartition(i)
				c.servers[i].CreatePartition(newLeader)
			}
		}

		// Wait for a new leader in the majority partition
		time.Sleep(2 * time.Second)

		// Find the new leader in the majority partition
		majorityLeader := -1
		for i, server := range c.servers {
			if contains(partitionedServers, i) {
				continue
			}

			state, _, _, active := server.GetState()
			if active && state == Leader {
				majorityLeader = i
				break
			}
		}

		if majorityLeader != -1 {
			c.logger.Printf("New leader in majority partition is Server %d\n", majorityLeader)

			// Add commands to the majority partition
			c.logger.Println("TEST 6: Adding commands to majority partition")
			for i := 10; i < 15; i++ {
				cmd := fmt.Sprintf("command-%d", i)
				if !c.servers[majorityLeader].AppendCommand(cmd) {
					c.logger.Printf("Failed to append command %s\n", cmd)
				}
				time.Sleep(100 * time.Millisecond)
			}
		} else {
			c.logger.Println("No leader elected in majority partition")
		}

		// Test 5: Heal the partition
		c.logger.Println("TEST 7: Healing network partition")
		for i := 0; i < len(c.servers); i++ {
			if i != newLeader {
				c.servers[newLeader].HealPartition(i)
				c.servers[i].HealPartition(newLeader)
			}
		}

		// Wait for the cluster to stabilize
		time.Sleep(2 * time.Second)
	}

	// Test 6: Multiple node failures
	c.logger.Println("TEST 8: Multiple node failures")
	failCount := len(c.servers) / 2 // Crash half the cluster
	for i := 0; i < failCount; i++ {
		c.servers[i].Crash()
	}

	// Wait to see if the cluster maintains availability
	time.Sleep(2 * time.Second)

	// Find the current leader, if any
	currentLeader := c.findCurrentLeader()

	if currentLeader != -1 {
		c.logger.Printf("Leader after multiple failures is Server %d\n", currentLeader)

		// Add commands to ensure the cluster is still functioning
		c.logger.Println("TEST 9: Adding commands after multiple failures")
		for i := 15; i < 20; i++ {
			cmd := fmt.Sprintf("command-%d", i)
			if !c.servers[currentLeader].AppendCommand(cmd) {
				c.logger.Printf("Failed to append command %s\n", cmd)
			}
			time.Sleep(100 * time.Millisecond)
		}
	} else {
		c.logger.Println("No leader elected after multiple failures")
	}

	// Test 7: Restart all nodes
	c.logger.Println("TEST 10: Restarting all failed nodes")
	for i := 0; i < failCount; i++ {
		c.servers[i].Restart()
	}

	// Wait for the cluster to stabilize
	time.Sleep(3 * time.Second)

	// Verify log consistency
	c.VerifyLogsConsistency()

	c.logger.Println("Fault injection tests completed")
}

// findCurrentLeader returns the index of the current leader, or -1 if none
func (c *Cluster) findCurrentLeader() int {
	for i, server := range c.servers {
		state, _, _, active := server.GetState()
		if active && state == Leader {
			return i
		}
	}
	return -1
}

// VerifyLogsConsistency checks log consistency across all servers
func (c *Cluster) VerifyLogsConsistency() {
	c.logger.Println("Verifying log consistency across the cluster")

	activeServers := make([]*RaftServer, 0)
	for _, server := range c.servers {
		_, _, _, active := server.GetState()
		if active {
			activeServers = append(activeServers, server)
		}
	}

	if len(activeServers) <= 1 {
		c.logger.Println("Not enough active servers to verify consistency")
		return
	}

	// Find the server with the highest commit index
	var referenceServer *RaftServer
	highestCommit := -1

	for _, server := range activeServers {
		_, _, commitIndex, _ := server.GetState()
		if commitIndex > highestCommit {
			highestCommit = commitIndex
			referenceServer = server
		}
	}

	if highestCommit <= 0 {
		c.logger.Println("No committed entries to verify")
		return
	}

	// Get the reference log entries
	referenceServer.mu.Lock()
	referenceLog := make([]LogEntry, len(referenceServer.log))
	copy(referenceLog, referenceServer.log)
	referenceCommit := referenceServer.commitIndex
	referenceServer.mu.Unlock()

	// Check each active server's log against the reference
	inconsistencies := 0

	for _, server := range activeServers {
		if server == referenceServer {
			continue
		}

		server.mu.Lock()
		serverCommit := server.commitIndex
		serverLog := make([]LogEntry, len(server.log))
		copy(serverLog, server.log)
		server.mu.Unlock()

		// Check committed entries
		minCommit := min(referenceCommit, serverCommit)

		for i := 1; i <= minCommit; i++ { // Skip dummy entry at index 0
			if i >= len(referenceLog) || i >= len(serverLog) {
				c.logger.Printf("Log length mismatch for committed entries")
				inconsistencies++
				break
			}

			if referenceLog[i].Term != serverLog[i].Term || referenceLog[i].Command != serverLog[i].Command {
				c.logger.Printf("Log inconsistency at index %d: ref=(%d,%s) vs server=(%d,%s)",
					i, referenceLog[i].Term, referenceLog[i].Command,
					serverLog[i].Term, serverLog[i].Command)
				inconsistencies++
			}
		}
	}

	if inconsistencies == 0 {
		c.logger.Println("All committed logs are consistent across servers")
	} else {
		c.logger.Printf("Found %d log inconsistencies\n", inconsistencies)
	}
}

// min returns the minimum of two integers
func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

// contains checks if a slice contains a value
func contains(slice []int, val int) bool {
	for _, item := range slice {
		if item == val {
			return true
		}
	}
	return false
}

func main() {
	// Seed random number generator
	rand.Seed(time.Now().UnixNano())

	// Create a cluster with 5 servers
	cluster := CreateCluster(5)

	// Run fault injection tests
	cluster.RunFaultInjectionTests()

	// Keep the program running to see logs
	fmt.Println("Raft simulation running. Press Ctrl+C to stop.")
	select {} // Block forever
}

