        payload.put("event", "payment.completed");
        payload.put("payment_id", "pay_123456");
        payload.put("amount", "100.00");
        payload.put("currency", "USD");
        return payload;
    }

    private String generateHmacSignature(String timestamp, Map<String, Object> payload) throws Exception {
        String payloadJson = objectMapper.writeValueAsString(payload);
        String signaturePayload = timestamp + "." + payloadJson;

        Mac sha256Hmac = Mac.getInstance("HmacSHA256");
        SecretKeySpec secretKey = new SecretKeySpec(
            WEBHOOK_SECRET.getBytes(StandardCharsets.UTF_8), 
            "HmacSHA256"
        );
        sha256Hmac.init(secretKey);

        byte[] signedData = sha256Hmac.doFinal(signaturePayload.getBytes(StandardCharsets.UTF_8));
