                // If connection was closed, try to reconnect
                task::sleep(std::time::Duration::from_secs(1)).await;
            },
            Err(e) => {
                eprintln!("Failed to connect: {}", e);
                // Wait before retry
                task::sleep(std::time::Duration::from_secs(5)).await;
            },
        };
    }
}

async fn health_check(_: Request<Arc<TelemetryState>>) -> tide::Result {
    Ok("Service is up and running".into())
}

#[async_std::main]
async fn main() -> tide::Result<()> {
    let state = Arc::new(TelemetryState::new());

    // Start telemetry client in background
    let telemetry_state = state.clone();
    task::spawn(async move {
        telemetry_server(telemetry_state).await;
    });

    // Start HTTP server for health checks
    let mut app = tide::with_state(state);
    app.at("/health").get(health_check);
