// server.js - Entry point for scalable chat application
const express = require('express');
const http = require('http');
const socketIO = require('socket.io');
const redisAdapter = require('socket.io-redis');
const cluster = require('cluster');
const os = require('os');
const sticky = require('sticky-session');

const PORT = process.env.PORT || 3000;
const REDIS_HOST = process.env.REDIS_HOST || '127.0.0.1';
const REDIS_PORT = process.env.REDIS_PORT || 6379;

if (cluster.isMaster) {
  const numCPUs = os.cpus().length;

  console.log(`Master ${process.pid} is running`);

  // Fork workers.
  for (let i = 0; i < numCPUs; i++) {
    cluster.fork();
  }

  cluster.on('exit', (worker, code, signal) => {
    console.log(`worker ${worker.process.pid} died`);
    cluster.fork(); // Auto-restart worker
  });
} else {
  const app = express();
  const server = http.createServer(app);
  const io = socketIO(server);

  // Configure Redis adapter for horizontal scaling
  io.adapter(redisAdapter({ host: REDIS_HOST, port: REDIS_PORT }));

  // Socket.IO connection handling
  io.on('connection', (socket) => {
    console.log('A user connected', socket.id);

    // Handle incoming chat messages
    socket.on('chat message', (msg) => {
      console.log('message: ' + msg);
      // Broadcast to all connected clients across all instances
      io.emit('chat message', msg);
    });

    // Handle user disconnect
    socket.on('disconnect', () => {
      console.log('User disconnected');
    });
  });

  // Health check endpoint for load balancers
  app.get('/health', (req, res) => {
    res.status(200).send('OK');
  });

  // Using sticky-session to ensure that connections are sticky to a single process
  if (!sticky.listen(server, PORT)) {
    server.once('listening', function () {
      console.log(`Server started on port ${PORT} and process ${process.pid}`);
    });
  } else {
    console.log(`Worker ${process.pid} started`);
  }
}

// loadTest.js - Load testing script for 100k concurrent connections
const io = require('socket.io-client');
const TARGET_URL = 'http://localhost:3000';

let userCount = 100000; // Total number of concurrent connections
let connectedUsers = 0;
let messagesReceived = 0;

console.log(`Starting load test with ${userCount} concurrent connections...`);

let promises = [];

for (let i = 0; i < userCount; i++) {
    promises.push(new Promise((resolve, reject) => {
        let socket = io(TARGET_URL, {
            transports: ['websocket'],
            forceNew: true
        });

        socket.on('connect', () => {
            connectedUsers++;
            if (connectedUsers % 1000 === 0) {
                console.log(`${connectedUsers} users connected`);
            }

            // Listen for chat messages
            socket.on('chat message', (msg) => {
                messagesReceived++;
                if (messagesReceived % 10000 === 0) {
                    console.log(`Messages received: ${messagesReceived}`);
                }
            });

            // Simulate sending messages at intervals
            const messageInterval = setInterval(() => {
                socket.emit('chat message', `Message from user ${i} at ${Date.now()}`);
            }, Math.random() * 5000 + 5000); // Random interval between 5-10 seconds

            // Clean up on disconnect
            socket.on('disconnect', () => {
                clearInterval(messageInterval);
                console.log(`User ${i} disconnected`);
            });

            resolve(socket);
        });

        socket.on('connect_error', (error) => {
            console.error(`Connection error for user ${i}:`, error.message);
            reject(error);
        });

        // Timeout handling
        setTimeout(() => {
            if (!socket.connected) {
                reject(new Error(`Connection timeout for user ${i}`));
            }
        }, 10000);
    }));

    // Add delay between connections to prevent overwhelming
    if (i % 100 === 0) {
        await new Promise(resolve => setTimeout(resolve, 10));
    }
}

Promise.all(promises).then((sockets) => {
    console.log(`All ${userCount} users connected successfully!`);
    console.log('Load test running... Press Ctrl+C to stop');

    // Performance monitoring
    setInterval(() => {
        console.log(`Active connections: ${connectedUsers}, Messages received: ${messagesReceived}`);
    }, 10000);

}).catch((error) => {
    console.error('Error in connecting users:', error.message);
});

// Graceful shutdown
process.on('SIGINT', () => {
    console.log('\nShutting down load test...');
    process.exit(0);
});

