import { Component, OnInit } from '@angular/core';
import { CdkDragDrop, moveItemInArray } from '@angular/cdk/drag-drop';
import { Widget } from '../models/widget.model';
import { ConnectivityService } from '../services/connectivity.service';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss']
})
export class DashboardComponent implements OnInit {
  widgets: Widget[] = [
    { id: 1, name: 'Stock Performance', data: [], size: { width: 2, height: 1 } },
    { id: 2, name: 'Portfolio Value', data: [], size: { width: 1, height: 1 } },
    { id: 3, name: 'Market Trends', data: [], size: { width: 2, height: 2 } },
    { id: 4, name: 'Currency Exchange', data: [], size: { width: 1, height: 1 } }
  ];

  isLoading = false;

  constructor(private connectivityService: ConnectivityService) {}

  ngOnInit() {
    this.connectivityService.isLoading$.subscribe(loading => {
      this.isLoading = loading;
    });

    // Load saved layout if available
    const savedLayout = this.connectivityService.loadLayout();
    if (savedLayout) {
      this.widgets = savedLayout;
    }

    // Load data for each widget
    this.widgets.forEach(widget => {
      this.loadWidgetData(widget);
    });
  }

  drop(event: CdkDragDrop<Widget[]>) {
    moveItemInArray(this.widgets, event.previousIndex, event.currentIndex);
    this.connectivityService.saveLayout(this.widgets);
  }

  loadWidgetData(widget: Widget) {
    this.connectivityService.fetchFinancialData(widget.id).subscribe(data => {
      widget.data = data;
    });
  }

  onWidgetResize(widget: Widget, newSize: { width: number, height: number }) {
    widget.size = newSize;
    this.connectivityService.saveLayout(this.widgets);
  }

  addWidget() {
    const newId = this.widgets.length > 0 ? 
      Math.max(...this.widgets.map(w => w.id)) + 1 : 1;

    const newWidget: Widget = {
      id: newId,
      name: `Widget ${newId}`,
      data: [],
      size: { width: 1, height: 1 }
    };

    this.widgets.push(newWidget);
    this.loadWidgetData(newWidget);
  }

  removeWidget(index: number) {
    this.widgets.splice(index, 1);
    this.connectivityService.saveLayout(this.widgets);
  }
}

