import { Component, Input, Output, EventEmitter, OnInit } from '@angular/core';
import { Widget } from '../models/widget.model';
import { Chart } from 'angular-highcharts';

@Component({
  selector: 'app-widget',
  templateUrl: './widget.component.html',
  styleUrls: ['./widget.component.scss']
})
export class WidgetComponent implements OnInit {
  @Input() widget: Widget;
  @Input() isLoading = false;
  @Output() onResize = new EventEmitter<{width: number, height: number}>();
  @Output() onRemove = new EventEmitter<void>();

  chart: Chart;
  isResizing = false;

  ngOnInit() {
    this.initChart();
  }

  initChart() {
    this.chart = new Chart({
      chart: { 
        type: 'line',
        events: {
          render: () => {
            if (this.widget.data && this.widget.data.length > 0) {
              this.chart.ref$.subscribe(ref => {
                if (ref) {
                  ref.series[0].setData(this.widget.data);
                }
              });
            }
          }
        }
      },
      title: { text: this.widget.name },
      credits: { enabled: false },
      series: [{
        name: 'Data',
        data: this.widget.data.length ? this.widget.data : [0, 0, 0]
      }],
      tooltip: {
        formatter: function() {
          return `<b>${this.series.name}</b><br/>Value: ${this.y}`;
        }
      }
    });
  }

  startResize() {
    this.isResizing = true;
  }

  resize(width: number, height: number) {
    if (this.isResizing) {
      this.onResize.emit({ width, height });

      // Redraw chart after resize
      setTimeout(() => {
        if (this.chart && this.chart.ref) {
          this.chart.ref$.subscribe(ref => {
            if (ref) {
              ref.reflow();
            }
          });
        }
      }, 100);
    }
  }

  stopResize() {
    this.isResizing = false;
  }

  removeWidget() {
    this.onRemove.emit();
  }
}

